let $addButtonSection=document.getElementById("section_addCollection");let $blockCollection=document.getElementById("section_collection");if($blockCollection){deleteSection($blockCollection);deleteField($blockCollection);$addButtonSection.addEventListener("click",function(){let newForm=this.dataset.prototype;let index=this.dataset.index*1;newForm=newForm.replace(/__name__/g,index);newForm=newForm.replace(/__FIELDS_INDEX__/g,1);let div=document.createElement("div");div.id="item-collection-section-"+index;div.classList.add("card");div.classList.add("card-flush");div.classList.add("p-4");div.classList.add("mb-3");div.classList.add("item-collection-section");div.innerHTML=newForm;$blockCollection.append(div);let field=document.getElementById("field-collection-"+index);field.innerHTML=field.innerHTML.replace(/__FIELDS__/g,"0").replace(/__FIELD_SORT__/g,"100");deleteSection(div);deleteField(div);this.dataset.index=(index+1).toString()})}function deleteSection($block){let $delItem=$block.querySelectorAll(".del-item-section");$delItem.forEach(function(item){item.addEventListener("click",function(){let $counter=$block.getElementsByClassName("item-collection-section").length;if($counter>1){item.closest(".item-collection-section").remove()}else{alert("Минимально должна быть добавлена одна секция")}})})}function deleteField($block){let $delItem=$block.querySelectorAll(".del-item-field");$delItem.forEach(function(item){item.addEventListener("click",function(){console.log($block);console.log($block.querySelectorAll(".item-collection-field"));let $counter=$block.querySelectorAll(".item-collection-field").length;if($counter>1){item.closest(".item-collection-field").remove()}else{alert("Минимально должна быть добавлена одна секция")}})})}function createSectionField($btnAddFields){let newForm=$btnAddFields.dataset.prototype;let section_id=$btnAddFields.dataset.section;let index=$btnAddFields.dataset.index;newForm=newForm.replace(/__name__/g,section_id);newForm=newForm.replace(/__FIELDS__/g,index);newForm=newForm.replace(/__FIELD_SORT__/g,index*100+100);let div=document.createElement("div");div.id="item-collection-field-"+index;div.classList.add("item-collection-field");div.classList.add("pb-3");div.innerHTML=newForm;document.getElementById("field-collection-"+section_id).append(div);deleteField(div);$btnAddFields.dataset.index=(index*1+1).toString()}let $addButtonOffers=document.getElementById("offers_addCollection");let $blockCollectionOffers=document.getElementById("offers_collection");if($blockCollectionOffers){let $delItemOffers=$blockCollectionOffers.querySelectorAll(".del-item-offers");$delItemOffers.forEach(function(item){item.addEventListener("click",function(){item.closest(".item-collection-offers").remove()})});$addButtonOffers.addEventListener("click",function(){let newForm=this.dataset.prototype;let index=this.dataset.index;newForm=newForm.replace(/__name__/g,index);newForm=newForm.replace(/__OFFER_SORT__/g,index*100+100);let div=document.createElement("div");div.innerHTML=newForm;$blockCollectionOffers.append(div);div.querySelector(".del-item-offers").addEventListener("click",function(){this.closest(".item-collection-offers").remove()});this.dataset.index=(index*1+1).toString();$blockCollectionOffers.querySelectorAll(".is-reference").forEach(function(isReference){isReference.addEventListener("change",function(){chanfeReferenc(this)})})});$blockCollectionOffers.querySelectorAll(".is-reference").forEach(function(isReference){chanfeReferenc(isReference);isReference.addEventListener("change",function(){chanfeReferenc(this)})})}let $name=document.querySelector("input[data-lang='category_form_trans_0_"+$lang+"']");if($name){$name.addEventListener("input",catUrl.debounce(500));function catUrl(){document.getElementById("category_form_info_url").value=translitRuEn(this.value).toLowerCase()}}function chanfeReferenc($this){let ref=document.getElementById($this.dataset.reference);let multipleDiv=document.getElementById("multiple_"+$this.dataset.multiple);let multiple=document.getElementById($this.dataset.multiple);if($this.checked===true){ref.classList.remove("d-none");multipleDiv.classList.remove("d-none")}else{multipleDiv.classList.add("d-none");multiple.checked=false;ref.classList.add("d-none");ref.selectedIndex=0}}